import React, { useEffect, useState } from 'react';
import { get, post, put, remove } from '../api';

const emptyRhyme = {
  title: '',
  youtubeUrl: '',
  isThisGurbani: false,
  ageGroup: '',
  isActive: true,
};

const RhymesList = () => {
  const [rhymes, setRhymes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [workingRhyme, setWorkingRhyme] = useState(emptyRhyme);
  const [editingId, setEditingId] = useState(null);
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);

  const loadRhymes = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/rhymes');
      setRhymes(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load rhymes.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadRhymes();
  }, []);

  const handleRefresh = () => {
    loadRhymes();
  };

  const handleEdit = (rhyme) => {
    setEditingId(rhyme.id);
    setWorkingRhyme({
      title: rhyme.title || '',
      youtubeUrl: rhyme.youtubeUrl || '',
      isThisGurbani: rhyme.isThisGurbani || false,
      ageGroup: rhyme.ageGroup || '',
      isActive: rhyme.isActive,
    });
  };

  const handleCreate = () => {
    setEditingId(null);
    setWorkingRhyme(emptyRhyme);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSubmit = async () => {
    setActionError(null);
    setSuccessMessage(null);

    try {
      if (editingId) {
        await put(`/api/admin-lists/rhymes/${editingId}`, workingRhyme);
        setSuccessMessage('Rhyme updated successfully.');
      } else {
        await post('/api/admin-lists/rhymes', workingRhyme);
        setSuccessMessage('Rhyme created successfully.');
      }
      await loadRhymes();
      setEditingId(null);
      setWorkingRhyme(emptyRhyme);
    } catch (err) {
      console.error(err);
      setActionError('Unable to save rhyme.');
    }
  };

  const handleDelete = async (id) => {
    setActionError(null);
    setSuccessMessage(null);
    try {
      await remove(`/api/admin-lists/rhymes/${id}`);
      setSuccessMessage('Rhyme deleted successfully.');
      await loadRhymes();
    } catch (err) {
      console.error(err);
      setActionError('Unable to delete rhyme.');
    }
  };

  return (
    <div>
      <h2>Rhyme List</h2>
      <div style={{ marginBottom: 16 }}>
        <button onClick={handleRefresh} disabled={loading} style={{ marginRight: 8 }}>
          Refresh
        </button>
        <button onClick={handleCreate}>
          Add New Rhyme
        </button>
      </div>
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}
      {loading && <p>Loading rhymes...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Rhyme</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Youtube Link</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Is This Gurbani</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Age Group</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {rhymes.map((rhyme) => (
              <tr key={rhyme.id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{rhyme.title}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {rhyme.youtubeUrl ? (
                    <a href={rhyme.youtubeUrl} target="_blank" rel="noopener noreferrer">
                      Link
                    </a>
                  ) : (
                    'None'
                  )}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {rhyme.isThisGurbani ? 'Yes' : 'No'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{rhyme.ageGroup || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <button onClick={() => handleEdit(rhyme)} style={{ marginRight: 8 }}>
                    Edit
                  </button>
                  <button onClick={() => handleDelete(rhyme.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
      <div style={{ marginTop: 24, maxWidth: 600 }}>
        <h3>{editingId ? 'Edit Rhyme' : 'Add Rhyme'}</h3>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'block', marginBottom: 4 }}>Rhyme</label>
          <input
            type="text"
            value={workingRhyme.title}
            onChange={(e) => setWorkingRhyme({ ...workingRhyme, title: e.target.value })}
            style={{ width: '100%', padding: 8 }}
          />
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'block', marginBottom: 4 }}>Youtube Link</label>
          <input
            type="text"
            value={workingRhyme.youtubeUrl}
            onChange={(e) => setWorkingRhyme({ ...workingRhyme, youtubeUrl: e.target.value })}
            style={{ width: '100%', padding: 8 }}
          />
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'inline-flex', alignItems: 'center' }}>
            <input
              type="checkbox"
              checked={workingRhyme.isThisGurbani}
              onChange={(e) => setWorkingRhyme({ ...workingRhyme, isThisGurbani: e.target.checked })}
              style={{ marginRight: 8 }}
            />
            Is This Gurbani
          </label>
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'block', marginBottom: 4 }}>Age Group</label>
          <input
            type="text"
            value={workingRhyme.ageGroup}
            onChange={(e) => setWorkingRhyme({ ...workingRhyme, ageGroup: e.target.value })}
            style={{ width: '100%', padding: 8 }}
          />
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={{ display: 'inline-flex', alignItems: 'center' }}>
            <input
              type="checkbox"
              checked={workingRhyme.isActive}
              onChange={(e) => setWorkingRhyme({ ...workingRhyme, isActive: e.target.checked })}
              style={{ marginRight: 8 }}
            />
            Active
          </label>
        </div>
        <button onClick={handleSubmit} style={{ marginRight: 8 }}>
          Save
        </button>
      </div>
    </div>
  );
};

export default RhymesList;
